// Function to wait until a condition becomes true
function waitUntil(conditionFunction, timeoutSeconds, checkInterval) {
    timeoutSeconds = timeoutSeconds || 60;
    checkInterval = checkInterval || 0.5;
    var startTime = core.getJDay();
    var timeoutJD = startTime + timeoutSeconds / 86400;

    while (!conditionFunction() && core.getJDay() < timeoutJD) {
        core.wait(checkInterval);
    }
    return conditionFunction();
}

