// Function to get moon phase as string (Simple version)
function getMoonPhaseString() {
    var moonInfo = core.getObjectInfo("Moon");

    // Use built-in phase name if available (Stellarium 0.18.0+)
    if (moonInfo["phase-name"] !== undefined) {
        return moonInfo["phase-name"];
    }

    // Fallback for older versions
    var phase = moonInfo["phase"]; // 0-1 illumination
    var age = parseFloat(moonInfo["age"]); // Age in days

    if (isNaN(age) || age === undefined) {
        // Ultra fallback: illumination only
        if (phase < 0.02) return "New Moon";
        if (phase < 0.48) return "Waxing Crescent";
        if (phase < 0.52) return "First Quarter";
        if (phase < 0.98) return "Waxing Gibbous";
        if (phase <= 1.0) return "Full Moon";
        return "Unknown";
    }

    // Accurate method using both illumination and age
    if (phase < 0.02) {
        return "New Moon";
    }
    else if (phase < 0.48) {
        return (age < 14.8) ? "Waxing Crescent" : "Waning Crescent";
    }
    else if (phase < 0.52) {
        return (age < 14.8) ? "First Quarter" : "Third Quarter";
    }
    else if (phase < 0.98) {
        return (age < 14.8) ? "Waxing Gibbous" : "Waning Gibbous";
    }
    else {
        return "Full Moon";
    }
}

