function formatRaDec(ra, dec) {
    var raHours = ra / 15;
    var raH = Math.floor(raHours);
    var raM = Math.floor((raHours - raH) * 60);
    var raS = ((raHours - raH) * 60 - raM) * 60;
    return "RA: " + raH + "h " + raM + "m " + raS.toFixed(1) + "s, Dec: " + dec.toFixed(2) + "°";
}

