// Simple eclipse simulation
function simulateEclipse(eclipseJD, durationSeconds) {
    var originalRate = core.getTimeRate();
    core.setTimeRate(0);
    core.setJDay(eclipseJD);

    core.debug("Eclipse simulation started");
    core.moveToObject("Sun", 2);
    core.wait(2);
    StelMovementMgr.setFov(1.5);

    var startJD = core.getJDay();
    var endJD = startJD + durationSeconds / 86400;
    var totalSteps = 100;

    for (var step = 0; step <= totalSteps; step++) {
        var t = step / totalSteps;
        var currentJD = startJD + t * (endJD - startJD);
        core.setJDay(currentJD);

        var sunInfo = core.getObjectInfo("Sun");
        var eclipseMag = sunInfo["eclipse-magnitude"];
        if (eclipseMag) {
            core.debug("Eclipse magnitude: " + (eclipseMag * 100).toFixed(1) + "%");
        }

        core.wait(0.05);
    }

    core.setTimeRate(originalRate);
    core.debug("Eclipse simulation complete");
}

