// Find when two planets are closest in the sky
function findConjunction(planet1, planet2, startJD, endJD, steps) {
    var originalJD = core.getJDay();
    steps = steps || 1000;

    var bestJD = startJD;
    var bestDistance = Infinity;

    for (var i = 0; i <= steps; i++) {
        var t = i / steps;
        var currentJD = startJD + t * (endJD - startJD);
        core.setJDay(currentJD);

        var pos1 = core.getObjectInfo(planet1);
        var pos2 = core.getObjectInfo(planet2);

        // Calculate angular separation using spherical law of cosines
        var ra1 = pos1["ra"] * Math.PI / 180;
        var dec1 = pos1["dec"] * Math.PI / 180;
        var ra2 = pos2["ra"] * Math.PI / 180;
        var dec2 = pos2["dec"] * Math.PI / 180;

        var separation = Math.acos(
            Math.sin(dec1) * Math.sin(dec2) +
            Math.cos(dec1) * Math.cos(dec2) * Math.cos(ra1 - ra2)
        ) * 180 / Math.PI;

        if (separation < bestDistance) {
            bestDistance = separation;
            bestJD = currentJD;
        }
    }

    core.setJDay(bestJD);
    core.debug("Closest approach: " + bestDistance.toFixed(2) + "°");
    core.debug("Date: " + core.getDate("utc"));

    core.setJDay(originalJD);
    return bestJD;
}

