// Generate an observing plan based on current visibility
function generateObservingPlan() {
    var objects = [
        { name: "Sun", type: "star", minAlt: -6 },
        { name: "Moon", type: "moon", minAlt: 0 },
        { name: "Mercury", type: "planet", minAlt: 5 },
        { name: "Venus", type: "planet", minAlt: 5 },
        { name: "Mars", type: "planet", minAlt: 10 },
        { name: "Jupiter", type: "planet", minAlt: 10 },
        { name: "Saturn", type: "planet", minAlt: 10 },
        { name: "M31", type: "galaxy", minAlt: 15 },
        { name: "M42", type: "nebula", minAlt: 15 }
    ];

    core.resetOutput();
    core.output("=== OBSERVING PLAN ===");
    core.output("Generated: " + core.getDate("local"));
    core.output("Location: " + core.getObserverLocation());
    core.output("\n--- OBJECTS VISIBLE NOW ---\n");

    var visibleCount = 0;

    for (var i = 0; i < objects.length; i++) {
        var obj = objects[i];
        var info = core.getObjectInfo(obj.name);

        if (info && info["above-horizon"] && info["altitude"] > obj.minAlt) {
            visibleCount++;
            core.output(obj.name + ":");
            core.output("  Altitude: " + info["altitude"].toFixed(1) + "°");
            core.output("  Azimuth: " + info["azimuth"].toFixed(1) + "°");
            core.output("  Magnitude: " + info["vmag"]);
            core.output("");
        }
    }

    if (visibleCount === 0) {
        core.output("No objects visible at this time.");
        core.output("Try again when sky is darker.");
    }

    core.saveOutputAs("observing_plan.txt");
    core.debug("Observing plan saved to observing_plan.txt");
}

generateObservingPlan();

