function resetToNaturalSky() {
    core.debug("[Scripts] Resetting to natural sky...");

    // Sequential commands to reset all settings
    var commands = [
        "core.setDate('now')",
        "core.clear('natural')",
        "LabelMgr.deleteAllLabels()",
        "MarkerMgr.deleteAllMarkers()",
        "StelMovementMgr.setFlagTracking(false)",
        "StelMovementMgr.setEquatorialMount(false)",
        "core.goHome()",
        "LandscapeMgr.setFlagLandscape(true)",
        "LandscapeMgr.setFlagAtmosphere(true)",
        "StarMgr.setFlagStars(true)",
        "SolarSystem.setFlagPlanets(true)",
        "SolarSystem.setFlagLabels(true)",
        "NebulaMgr.setFlagShow(true)",
        "MilkyWay.setFlagShow(true)",
        "ConstellationMgr.setFlagLines(false)",
        "ConstellationMgr.setFlagLabels(false)",
        "ConstellationMgr.setFlagBoundaries(false)",
        "ConstellationMgr.setFlagArt(false)",
        "ConstellationMgr.setFlagIsolateSelected(false)",
        "ConstellationMgr.setFlagConstellationPick(false)",
        "GridLinesMgr.setFlagEquatorGrid(false)",
        "GridLinesMgr.setFlagAzimuthalGrid(false)",
        "LandscapeMgr.setFlagCardinalPoints(false)",
        "core.setNightMode(false)",
        "core.setGuiVisible(true)",
        "core.setDiskViewport(false)",
        "core.setProjectionMode('stereographic')",
        "core.moveToAltAzi(40.0, 180.0, 3.0)",
        "StelMovementMgr.zoomTo(90.0, 2.0)",
        "core.setTimeRate(1)"
    ];

    // Execute each command directly with small delay between them
    for (var i = 0; i < commands.length; i++) {
        core.debug("Executing command " + (i+1) + "/" + commands.length + ": " + commands[i]);
        try {
            eval(commands[i]);  // Execute natively like Stellarium's script engine
        } catch(e) {
            core.debug("Error executing command: " + commands[i] + " - " + e);
        }
        core.wait(0.1);  // Small delay to ensure each command completes
    }

    core.debug("[Scripts] ✓ Full reset completed successfully.");
}

